  ('optometrist-moex-02344', 'optometrist', 'optometrist-moex-108-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '張先生使用角膜弧度儀檢測得到患者角膜資訊：+43.25DS@180°；+44.00DS@90°。若使用光學十字表示， 下列何者正確？', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "c5e9f6546080", "answer_pdf_sha1": "39c1e9ea8581", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
